import java.util.Scanner;
import java.util.ArrayDeque;
import java.util.Deque;

/**
 * Diameter of a Binary Tree.
 *
 * The diameter is the number of EDGES on the longest path between any two nodes
 * in the tree. That path may or may not pass through the root.
 *
 * Key insight: for any node, the longest path that BENDS at that node has length
 *   height(left) + height(right)   (in edges),
 * where height(x) = number of edges on the longest downward path from x to a leaf
 * (height of a null child = -1 in edge terms, height of a single node = 0).
 * The answer is the maximum such "bent" length over all nodes, computed in a
 * single post-order traversal.
 */
public class Solution {

    /** Standard binary-tree node. */
    static class TreeNode {
        int val;
        TreeNode left, right;
        TreeNode(int val) { this.val = val; }
    }

    /** Tracks the best diameter found so far across the recursion. */
    private int best;

    /**
     * Returns the diameter (longest path length in edges) of the tree.
     * Empty tree (root == null) has diameter 0.
     */
    public int diameterOfBinaryTree(TreeNode root) {
        best = 0;
        height(root);
        return best;
    }

    /**
     * Post-order height in EDGES. Height of null is -1 so that a leaf
     * (null+null children) reports height 0, and a node's height is
     * 1 + max(childHeights). While here, update `best` with the path that
     * bends at this node: (heightLeft + 1) + (heightRight + 1) edges, i.e.
     * leftEdges + rightEdges where leftEdges = heightLeft + 1.
     */
    private int height(TreeNode node) {
        if (node == null) return -1;
        int hl = height(node.left);
        int hr = height(node.right);
        // Edges going down through left subtree + edges through right subtree.
        int through = (hl + 1) + (hr + 1);
        if (through > best) best = through;
        return Math.max(hl, hr) + 1;
    }

    // ------------------------------------------------------------------
    // I/O harness: builds a tree from a level-order line of tokens where
    // "null" marks an absent child (LeetCode-style), then prints the diameter.
    // Example input line:  1 2 3 null 4 5
    // ------------------------------------------------------------------
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextLine()) {
            System.out.println(new Solution().diameterOfBinaryTree(null));
            return;
        }
        String line = sc.nextLine().trim();
        TreeNode root = build(line);
        System.out.println(new Solution().diameterOfBinaryTree(root));
    }

    /** Build a tree from a space-separated level-order list ("null" = absent). */
    static TreeNode build(String line) {
        if (line.isEmpty()) return null;
        String[] tok = line.split("\\s+");
        if (tok.length == 0 || tok[0].equalsIgnoreCase("null")) return null;
        TreeNode root = new TreeNode(Integer.parseInt(tok[0]));
        Deque<TreeNode> q = new ArrayDeque<>();
        q.add(root);
        int i = 1;
        while (!q.isEmpty() && i < tok.length) {
            TreeNode cur = q.poll();
            if (i < tok.length && !tok[i].equalsIgnoreCase("null")) {
                cur.left = new TreeNode(Integer.parseInt(tok[i]));
                q.add(cur.left);
            }
            i++;
            if (i < tok.length && !tok[i].equalsIgnoreCase("null")) {
                cur.right = new TreeNode(Integer.parseInt(tok[i]));
                q.add(cur.right);
            }
            i++;
        }
        return root;
    }
}

/**
 * Test harness for Diameter of Binary Tree.
 * Builds trees programmatically and asserts expected diameters.
 */
public class Main {

    static int passed = 0, failed = 0;

    static Solution.TreeNode node(int v) { return new Solution.TreeNode(v); }

    static void check(String name, int got, int expected) {
        boolean ok = got == expected;
        if (ok) passed++; else failed++;
        System.out.printf("[%s] %-42s got=%d expected=%d%n",
                ok ? "PASS" : "FAIL", name, got, expected);
    }

    public static void main(String[] args) {
        Solution s = new Solution();

        // 1) Prompt example: root 1 -> (2,3); 2 -> (4,5). Path 4-2-1-3 = 3 edges.
        Solution.TreeNode r1 = node(1);
        r1.left = node(2); r1.right = node(3);
        r1.left.left = node(4); r1.left.right = node(5);
        check("example (path through root)", s.diameterOfBinaryTree(r1), 3);

        // 2) Empty tree -> 0 edges.
        check("empty tree", s.diameterOfBinaryTree(null), 0);

        // 3) Single node -> 0 edges (no path).
        check("single node", s.diameterOfBinaryTree(node(7)), 0);

        // 4) Two nodes (root + one child) -> 1 edge.
        Solution.TreeNode r4 = node(1); r4.left = node(2);
        check("two nodes", s.diameterOfBinaryTree(r4), 1);

        // 5) Left-skewed chain of 5 nodes -> 4 edges.
        Solution.TreeNode r5 = node(1), cur5 = r5;
        for (int i = 2; i <= 5; i++) { cur5.left = node(i); cur5 = cur5.left; }
        check("left-skewed chain (5)", s.diameterOfBinaryTree(r5), 4);

        // 6) Right-skewed chain of 6 nodes -> 5 edges.
        Solution.TreeNode r6 = node(1), cur6 = r6;
        for (int i = 2; i <= 6; i++) { cur6.right = node(i); cur6 = cur6.right; }
        check("right-skewed chain (6)", s.diameterOfBinaryTree(r6), 5);

        // 7) Path NOT through root: deep left subtree, shallow right.
        //    root(1) -> left chain of length 4 down + that left node also has a
        //    sibling depth; longest path stays within the left subtree.
        //        1
        //       /
        //      2
        //     / \
        //    3   4
        //   /     \
        //  5       6
        // Longest = 5-3-2-4-6 = 4 edges, never touching root 1.
        Solution.TreeNode r7 = node(1);
        r7.left = node(2);
        r7.left.left = node(3);
        r7.left.right = node(4);
        r7.left.left.left = node(5);
        r7.left.right.right = node(6);
        check("path NOT through root", s.diameterOfBinaryTree(r7), 4);

        // 8) Balanced perfect tree of height 3 (15 nodes) -> diameter 2*3 = 6.
        check("perfect tree height 3", s.diameterOfBinaryTree(perfect(3)), 6);

        // 9) Diameter through root with unequal arms:
        //    left depth 2, right depth 3 -> 2 + 3 = 5 edges.
        Solution.TreeNode r9 = node(0);
        Solution.TreeNode l = r9; for (int i = 0; i < 2; i++) { l.left = node(1); l = l.left; }
        Solution.TreeNode rr = r9; for (int i = 0; i < 3; i++) { rr.right = node(1); rr = rr.right; }
        check("through root unequal arms", s.diameterOfBinaryTree(r9), 5);

        // 10) Large stress: left-skewed chain of 10^4 nodes -> 9999 edges.
        //     Verifies no stack overflow / correctness at max constraint.
        int N = 10000;
        Solution.TreeNode big = node(0), cb = big;
        for (int i = 1; i < N; i++) { cb.left = node(i); cb = cb.left; }
        check("stress left chain 10^4", s.diameterOfBinaryTree(big), N - 1);

        // 11) Large stress: perfect tree with > 10^4 nodes (height 13 -> 16383
        //     nodes), diameter = 2*13 = 26.
        check("stress perfect tree (16383 nodes)", s.diameterOfBinaryTree(perfect(13)), 26);

        // 12) build()-based parse sanity: "1 2 3 null 4 5" matches example shape
        //     1 -> (2,3); 2 -> (null,4); 3 -> (5, ...). Path 4-2-1-3-5 = 4 edges.
        Solution.TreeNode rb = Solution.build("1 2 3 null 4 5");
        check("level-order parse", s.diameterOfBinaryTree(rb), 4);

        System.out.printf("%n==== %d passed, %d failed ====%n", passed, failed);
        if (failed > 0) System.exit(1);
    }

    /** Build a perfect binary tree of the given height (edges from root to leaf). */
    static Solution.TreeNode perfect(int height) {
        if (height < 0) return null;
        Solution.TreeNode n = node(0);
        if (height > 0) { n.left = perfect(height - 1); n.right = perfect(height - 1); }
        return n;
    }
}

# Diameter of Binary Tree

## 1. Problem Analysis

- **Input:** the root of a binary tree (each node holds an `int` and up to two children).
- **Output:** an integer — the **diameter**, defined as the length in **edges** of the longest path between any two nodes. That path may bend at any node and need not pass through the root.
- **Constraints:** `1 <= number of nodes <= 10^4`.

What the constraints dictate:
- `n <= 10^4` is tiny — anything up to O(n^2) would technically pass, but the clean optimum here is **O(n)** with a single traversal.
- The metric is **edges, not nodes**. A single node has diameter `0`; an edge between two nodes counts as `1`. The example confirms this: root `1` with children `2,3`, and `2` with children `4,5`, gives the path `4 -> 2 -> 1 -> 3` of length **3 edges**.
- No value-arithmetic is involved (we count structure, not sum node values), so there is **no integer-overflow risk**: the maximum diameter is bounded by `n - 1 <= 9999`, which fits comfortably in `int`.

## 2. Strategy

**Brute force:** for every node, compute the height of its left and right subtrees and combine them; recomputing heights from scratch at each node is O(n) per node => **O(n^2)** overall. The bottleneck is repeated height recomputation.

**Optimal approach — one post-order DFS:** the longest path that *bends* at a given node equals `leftEdges + rightEdges`, where `leftEdges` / `rightEdges` are the number of edges on the deepest downward path into each subtree. If we compute height bottom-up, every node already knows its children's heights, so we can update a running best diameter *while* computing heights — no recomputation.

Define `height(x)` in **edges**: `height(null) = -1`, so a leaf reports `0` and any node is `1 + max(childHeights)`. At each node the bent path is `(heightLeft + 1) + (heightRight + 1)` edges; take the global max.

- **Time:** O(n) — each node visited once.
- **Space:** O(h) recursion stack, where `h` is tree height (O(n) worst case for a skewed tree, O(log n) when balanced).

